{
  "E": [
    "You arrive at a party where you know no one. Describe your next hour.",
    "Your weekend is completely free. Walk me through your ideal Saturday."
  ],
  "O": [
    "You are handed a tool you have never seen. What do you do with it?",
    "Describe a place you would most want to visit and why."
  ],
  "C": [
    "You have a week to finish a big project. Describe how you start.",
    "Your desk is a mess before a deadline. What happens next?"
  ],
  "A": [
    "A coworker takes credit for your idea in a meeting. What do you say and do?",
    "A stranger asks you for directions while you are in a hurry."
  ],
  "N": [
    "You get an unexpected, vaguely worded message from your boss. How do you feel and react?",
    "Your plans fall through at the last minute. Describe the next ten minutes."
  ]
}

{
  "E": [
    "Your team just hit a deadline early — what do you do with the spare afternoon?",
    "You are seated next to a quiet colleague at a long training session. How does the time unfold?"
  ],
  "O": [
    "You inherit a collection of books written in a language you cannot read. What do you do with them?",
    "A friend offers you a ticket to a performance of music you have never heard before. Walk through your evening."
  ],
  "C": [
    "You wake up and notice that your daily routine has been disrupted by an unexpected power outage. How do you handle your morning?",
    "You have two weeks of vacation coming up. How do you prepare before you leave?"
  ],
  "A": [
    "A junior colleague confesses they made a costly mistake on a report before it was submitted. What do you do?",
    "You notice that a neighbour seems to be struggling carrying heavy groceries up the stairs. Walk through how you respond."
  ],
  "N": [
    "You discover that a flight you booked has been cancelled with no rescheduled option given yet. How do you respond over the next hour?",
    "A medical check-up result comes back marked as needing a follow-up consultation. Describe the next twenty-four hours."
  ]
}

{
  "description": "Small, sourced concept->tradition lexicon that drives the ontology_edge_faithful surface gate. Each concept term is tagged with the tradition it belongs to so the gate can fire on an asserted cross-tradition IDENTITY/SUBSUMPTION (e.g. 'ren is identical to agape') while passing a scoped analogy ('wu wei resembles apatheia'). Keep small, versioned, provenance-tagged; this is a closed-world lexicon, not a truth oracle. See docs/11-Platform/Ontology-Claim-Boundary.md.",
  "source": "Standard reference glosses: ren (Analects/Confucian ethics), agape (NT Greek / Christian theology), wu wei (Dao De Jing / Daoist), apatheia (Stoic / Hellenistic philosophy), nirvana (Buddhist soteriology), moksha (Hindu/Vedantic), li (Confucian ritual propriety), de (Daoist/Confucian virtue-power), karuna (Buddhist compassion), caritas (Latin Christian charity), eudaimonia (Aristotelian flourishing), ataraxia (Epicurean/Pyrrhonist tranquillity)."
}

